20: // needed to mock the function for testing
21: var shouldCacheQuery = awsds.ShouldCacheQuery
22: 
23: // NewCachingMiddleware creates a new backend.HandlerMiddleware that will
24: // attempt to read and write query results to the cache
25: func NewCachingMiddleware(cachingService caching.CachingService) backend.HandlerMiddleware {
26: 	return NewCachingMiddlewareWithFeatureManager(cachingService, nil)
27: }
28: 
29: // NewCachingMiddlewareWithFeatureManager creates a new backend.HandlerMiddleware that will
30: // attempt to read and write query results to the cache with a feature manager
31: func NewCachingMiddlewareWithFeatureManager(cachingService caching.CachingService, features featuremgmt.FeatureToggles) backend.HandlerMiddleware {
32: 	log := log.New("caching_middleware")
33: 	if err := prometheus.Register(QueryCachingRequestHistogram); err != nil {
34: 		log.Error("Error registering prometheus collector 'QueryRequestHistogram'", "error", err)
35: 	}
36: 	if err := prometheus.Register(ResourceCachingRequestHistogram); err != nil {
37: 		log.Error("Error registering prometheus collector 'ResourceRequestHistogram'", "error", err)
38: 	}
39: 	cachingMiddlewareHandler := func(next backend.Handler) backend.Handler {
40: 		cachingMiddleware := &CachingMiddleware{
41: 			BaseHandler: backend.NewBaseHandler(next),
42: 			caching:     cachingService,
43: 			log:         log,
44: 			features:    features,
45: 		}
46: 		if features != nil && features.IsEnabled(context.Background(), featuremgmt.FlagQueryCacheRequestDeduplication) {
47: 			return newRequestDeduplicationMiddleware(log, cachingMiddleware)
48: 		}
49: 		return cachingMiddleware
50: 	}
51: 
52: 	return backend.HandlerMiddlewareFunc(cachingMiddlewareHandler)
53: }
54: 
55: type CachingMiddleware struct {
56: 	backend.BaseHandler
57: 
58: 	caching  caching.CachingService
59: 	log      log.Logger
60: 	features featuremgmt.FeatureToggles
61: }
62: 
63: // QueryData receives a data request and attempts to access results already stored in the cache for that request.
64: // If data is found, it will return it immediately. Otherwise, it will perform the queries as usual, then write the response to the cache.
65: // If the cache service is implemented, we capture the request duration as a metric. The service is expected to write any response headers.
66: func (m *CachingMiddleware) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
67: 	if req == nil {
68: 		return m.BaseHandler.QueryData(ctx, req)
69: 	}
70: 
71: 	reqCtx := contexthandler.FromContext(ctx)
72: 	if reqCtx == nil {
73: 		return m.BaseHandler.QueryData(ctx, req)
74: 	}
75: 
76: 	// time how long this request takes
77: 	start := time.Now()
78: 
79: 	// First look in the query cache if enabled
80: 	hit, cr := m.caching.HandleQueryRequest(ctx, req)
81: 
82: 	// record request duration if caching was used
83: 	ch := reqCtx.Resp.Header().Get(caching.XCacheHeader)
84: 	if ch != "" {
85: 		defer func() {
86: 			QueryCachingRequestHistogram.With(prometheus.Labels{
87: 				"datasource_type": req.PluginContext.DataSourceInstanceSettings.Type,
88: 				"cache":           ch,
89: 				"query_type":      getQueryType(reqCtx),
90: 			}).Observe(time.Since(start).Seconds())
91: 		}()
92: 	}
93: 
94: 	// Cache hit; return the response
95: 	if hit {
96: 		return cr.Response, nil
97: 	}
98: 
99: 	// Cache miss; do the actual queries
100: 	resp, err := m.BaseHandler.QueryData(ctx, req)
101: 
102: 	// Update the query cache with the result for this metrics request
103: 	if err == nil && cr.UpdateCacheFn != nil {
104: 		// If AWS async caching is not enabled, use the old code path
105: 		if m.features == nil || !m.features.IsEnabled(ctx, featuremgmt.FlagAwsAsyncQueryCaching) {
106: 			cr.UpdateCacheFn(ctx, resp)
107: 		} else {
108: 			// time how long shouldCacheQuery takes
109: 			startShouldCacheQuery := time.Now()
110: 			shouldCache := shouldCacheQuery(resp)
111: 			ShouldCacheQueryHistogram.With(prometheus.Labels{
112: 				"datasource_type": req.PluginContext.DataSourceInstanceSettings.Type,
113: 				"cache":           ch,
114: 				"shouldCache":     strconv.FormatBool(shouldCache),
115: 				"query_type":      getQueryType(reqCtx),
116: 			}).Observe(time.Since(startShouldCacheQuery).Seconds())
117: 
118: 			// If AWS async caching is enabled and resp is for a running async query, don't cache it
119: 			if shouldCache {
120: 				cr.UpdateCacheFn(ctx, resp)
121: 			}
122: 		}
123: 	}
124: 
125: 	return resp, err
126: }
127: 
128: // CallResource receives a resource request and attempts to access results already stored in the cache for that request.
129: // If data is found, it will return it immediately. Otherwise, it will perform the request as usual. The caller of CallResource is expected to explicitly update the cache with any responses.
130: // If the cache service is implemented, we capture the request duration as a metric. The service is expected to write any response headers.
131: func (m *CachingMiddleware) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
132: 	if req == nil {
133: 		return m.BaseHandler.CallResource(ctx, req, sender)
134: 	}
135: 
136: 	reqCtx := contexthandler.FromContext(ctx)
137: 	if reqCtx == nil {
138: 		return m.BaseHandler.CallResource(ctx, req, sender)
139: 	}
140: 
141: 	// time how long this request takes
142: 	start := time.Now()
143: 
144: 	// First look in the resource cache if enabled
145: 	hit, cr := m.caching.HandleResourceRequest(ctx, req)
146: 
147: 	// record request duration if caching was used
148: 	if ch := reqCtx.Resp.Header().Get(caching.XCacheHeader); ch != "" {
149: 		defer func() {
150: 			ResourceCachingRequestHistogram.With(prometheus.Labels{
151: 				"plugin_id": req.PluginContext.PluginID,
152: 				"cache":     ch,
153: 			}).Observe(time.Since(start).Seconds())
154: 		}()
155: 	}
156: 
157: 	// Cache hit; send the response and return
158: 	if hit {
159: 		return sender.Send(cr.Response)
160: 	}
161: 
162: 	// Cache miss; do the actual request
163: 	// If there is no update cache func, just pass in the original sender
164: 	if cr.UpdateCacheFn == nil {
165: 		return m.BaseHandler.CallResource(ctx, req, sender)
166: 	}
167: 	// Otherwise, intercept the responses in a wrapped sender so we can cache them first
168: 	cacheSender := backend.CallResourceResponseSenderFunc(func(res *backend.CallResourceResponse) error {
169: 		cr.UpdateCacheFn(ctx, res)
170: 		return sender.Send(res)
171: 	})
172: 
173: 	return m.BaseHandler.CallResource(ctx, req, cacheSender)
174: }
175: 
176: // Given N requests happening at the same time and issuing the same query, only one request will execute
177: // and the other ones will wait for the response received by the request being executed.
178: type requestDeduplicationMiddleware struct {
179: 	backend.BaseHandler
180: 	log          *log.ConcreteLogger
181: 	singleflight *singleflight.Group
182: }
183: 
184: func newRequestDeduplicationMiddleware(log *log.ConcreteLogger, next backend.Handler) *requestDeduplicationMiddleware {
185: 	return &requestDeduplicationMiddleware{log: log, BaseHandler: backend.NewBaseHandler(next), singleflight: &singleflight.Group{}}
186: }
187: 
188: func (m *requestDeduplicationMiddleware) QueryData(ctx context.Context, req *backend.QueryDataRequest) (*backend.QueryDataResponse, error) {
189: 	if req.PluginContext.DataSourceInstanceSettings == nil || req.PluginContext.DataSourceInstanceSettings.UID == "" {
190: 		return m.BaseHandler.QueryData(ctx, req)
191: 	}
192: 	key, err := caching.GetKey(req.PluginContext.DataSourceInstanceSettings.UID, req)
193: 	if err != nil {
194: 		m.log.Error("error building cache key for request deduplication, skipping request deduplication", "error", err)
195: 		return m.BaseHandler.QueryData(ctx, req)
196: 	}
197: 	v, err, _ := m.singleflight.Do(key, func() (interface{}, error) {
198: 		return m.BaseHandler.QueryData(ctx, req)
199: 	})
200: 	if err != nil {
201: 		return nil, fmt.Errorf("request deduplication middleware: calling BaseHandler.QueryData: %w", err)
202: 	}
203: 	return v.(*backend.QueryDataResponse), nil
204: }
205: 
206: func (m *requestDeduplicationMiddleware) CallResource(ctx context.Context, req *backend.CallResourceRequest, sender backend.CallResourceResponseSender) error {
207: 	if req.PluginContext.DataSourceInstanceSettings == nil || req.PluginContext.DataSourceInstanceSettings.UID == "" {
208: 		return m.BaseHandler.CallResource(ctx, req, sender)
209: 	}
210: 
211: 	key, err := caching.GetKey(req.PluginContext.DataSourceInstanceSettings.UID, req)
212: 	if err != nil {
213: 		m.log.Error("error building cache key for request deduplication, skipping request deduplication", "error", err)
214: 		return m.BaseHandler.CallResource(ctx, req, sender)
215: 	}
216: 	_, err, _ = m.singleflight.Do(key, func() (interface{}, error) {
217: 		return nil, m.BaseHandler.CallResource(ctx, req, sender)
218: 	})
219: 	if err != nil {
220: 		return fmt.Errorf("request deduplication middleware: calling BaseHandler.CallResource: %w", err)
221: 	}
222: 	return nil
223: }
