72: // GetKey creates a prefixed cache key and uses the internal `encoder` to encode the query into a string
73: func GetKey(prefix string, query interface{}) (string, error) {
74: 	keybuf := bytes.NewBuffer(nil)
75: 
76: 	encoder := &JSONEncoder{}
77: 
78: 	if err := encoder.Encode(keybuf, query); err != nil {
79: 		return "", err
80: 	}
81: 
82: 	key, err := SHA256KeyFunc(keybuf)
83: 	if err != nil {
84: 		return "", err
85: 	}
86: 
87: 	return strings.Join([]string{prefix, key}, ":"), nil
88: }
89: 
90: // SHA256KeyFunc copies the data from `r` into a sha256.Hash, and returns the encoded Sum.
91: func SHA256KeyFunc(r io.Reader) (string, error) {
92: 	hash := sha256.New()
93: 
94: 	// Read all data from the provided reader
95: 	if _, err := io.Copy(hash, r); err != nil {
96: 		return "", err
97: 	}
98: 
99: 	// Encode the written values to SHA256
100: 	return hex.EncodeToString(hash.Sum(nil)), nil
101: }
102: 
103: // JSONEncoder encodes and decodes struct data to/from JSON
104: type JSONEncoder struct{}
105: 
106: // NewJSONEncoder creates a pointer to a new JSONEncoder, which implements the `Encoder` interface
107: func NewJSONEncoder() *JSONEncoder {
108: 	return &JSONEncoder{}
109: }
110: 
111: func (e *JSONEncoder) EncodeBytes(w io.Writer, b []byte) error {
112: 	_, err := w.Write(b)
113: 	if err != nil {
114: 		return err
115: 	}
116: 	return nil
117: }
118: 
119: func (e *JSONEncoder) DecodeBytes(r io.Reader) ([]byte, error) {
120: 	encBytes, err := io.ReadAll(r)
121: 	if err != nil {
122: 		return []byte{}, err
123: 	}
124: 	return encBytes, err
125: }
126: 
127: // Encode encodes the `v` interface into `w` using a json.Encoder
128: func (e *JSONEncoder) Encode(w io.Writer, v interface{}) error {
129: 	return json.NewEncoder(w).Encode(v)
130: }
131: 
132: // Decode encodes the io.Reader `r` into the interface `v` using a json.Decoder
133: func (e *JSONEncoder) Decode(r io.Reader, v interface{}) error {
134: 	return json.NewDecoder(r).Decode(v)
135: }
