{"content":"1: package remotecache
2: 
3: import (
4: 	"context"
5: 	"crypto/tls"
6: 	"errors"
7: 	"fmt"
8: 	"strconv"
9: 	"strings"
10: 	"time"
11: 
12: 	"github.com/redis/go-redis/v9"
13: 
14: 	"github.com/grafana/grafana/pkg/setting"
15: )
16: 
17: const redisCacheType = "redis"
18: 
19: type redisStorage struct {
20: 	c *redis.Client
21: }
22: 
23: // parseRedisConnStr parses k=v pairs in csv and builds a redis Options object
24: func parseRedisConnStr(connStr string) (*redis.Options, error) {
25: 	keyValueCSV := strings.Split(connStr, ",")
26: 	options := &redis.Options{Network: "tcp"}
27: 	setTLSIsTrue := false
28: 	for _, rawKeyValue := range keyValueCSV {
29: 		keyValueTuple := strings.SplitN(rawKeyValue, "=", 2)
30: 		if len(keyValueTuple) != 2 {
31: 			if strings.HasPrefix(rawKeyValue, "password") {
32: 				// don't log the password
33: 				rawKeyValue = "password" + setting.RedactedPassword
34: 			}
35: 			return nil, fmt.Errorf("incorrect redis connection string format detected for '%v', format is key=value,key=value", rawKeyValue)
36: 		}
37: 		connKey := keyValueTuple[0]
38: 		connVal := keyValueTuple[1]
39: 		switch connKey {
40: 		case "addr":
41: 			options.Addr = connVal
42: 		case "username":
43: 			options.Username = connVal
44: 		case "password":
45: 			options.Password = connVal
46: 		case "db":
47: 			i, err := strconv.Atoi(connVal)
48: 			if err != nil {
49: 				return nil, fmt.Errorf("%v: %w", "value for db in redis connection string must be a number", err)
50: 			}
51: 			options.DB = i
52: 		case "pool_size":
53: 			i, err := strconv.Atoi(connVal)
54: 			if err != nil {
55: 				return nil, fmt.Errorf("%v: %w", "value for pool_size in redis connection string must be a number", err)
56: 			}
57: 			options.PoolSize = i
58: 		case "ssl":
59: 			if connVal != "true" && connVal != "false" && connVal != "insecure" {
60: 				return nil, fmt.Errorf("ssl must be set to 'true', 'false', or 'insecure' when present")
61: 			}
62: 			if connVal == "true" {
63: 				setTLSIsTrue = true // Needs addr already parsed, so set later
64: 			}
65: 			if connVal == "insecure" {
66: 				options.TLSConfig = &tls.Config{InsecureSkipVerify: true}
67: 			}
68: 		default:
69: 			return nil, fmt.Errorf("unrecognized option '%v' in redis connection string", connKey)
70: 		}
71: 	}
72: 	if setTLSIsTrue {
73: 		// Get hostname from the Addr property and set it on the configuration for TLS
74: 		sp := strings.Split(options.Addr, ":")
75: 		if len(sp) < 1 {
76: 			return nil, fmt.Errorf("unable to get hostname from the addr field, expected host:port, got '%v'", options.Addr)
77: 		}
78: 		options.TLSConfig = &tls.Config{ServerName: sp[0]}
79: 	}
80: 	return options, nil
81: }
82: 
83: func newRedisStorage(opts *setting.RemoteCacheSettings) (*redisStorage, error) {
84: 	opt, err := parseRedisConnStr(opts.ConnStr)
85: 	if err != nil {
86: 		return nil, err
87: 	}
88: 	return &redisStorage{c: redis.NewClient(opt)}, nil
89: }
90: 
91: // Set sets value to a given key
92: func (s *redisStorage) Set(ctx context.Context, key string, data []byte, expires time.Duration) error {
93: 	status := s.c.Set(ctx, key, data, expires)
94: 	return status.Err()
95: }
96: 
97: // GetByteArray returns the value as byte array
98: func (s *redisStorage) Get(ctx context.Context, key string) ([]byte, error) {
99: 	item, err := s.c.Get(ctx, key).Bytes()
100: 	if err != nil {
101: 		if errors.Is(err, redis.Nil) {
102: 			return nil, ErrCacheItemNotFound
103: 		}
104: 		return nil, err
105: 	}
106: 
107: 	return item, nil
108: }
109: 
110: // Delete delete a key from session.
111: func (s *redisStorage) Delete(ctx context.Context, key string) error {
112: 	cmd := s.c.Del(ctx, key)
113: 	return cmd.Err()
114: }
