13: const memcachedCacheType = "memcached"
14: 
15: var ErrNotImplemented = errors.New("not implemented")
16: 
17: type memcachedStorage struct {
18: 	c *memcache.Client
19: }
20: 
21: func newMemcachedStorage(opts *setting.RemoteCacheSettings) *memcachedStorage {
22: 	return &memcachedStorage{
23: 		c: memcache.New(opts.ConnStr),
24: 	}
25: }
26: 
27: func newItem(sid string, data []byte, expire int32) *memcache.Item {
28: 	return &memcache.Item{
29: 		Key:        sid,
30: 		Value:      data,
31: 		Expiration: expire,
32: 	}
33: }
34: 
35: // SetByteArray stores an byte array in the cache
36: func (s *memcachedStorage) Set(ctx context.Context, key string, data []byte, expires time.Duration) error {
37: 	var expiresInSeconds int64
38: 	if expires != 0 {
39: 		expiresInSeconds = int64(expires) / int64(time.Second)
40: 	}
41: 
42: 	memcachedItem := newItem(key, data, int32(expiresInSeconds))
43: 	return s.c.Set(memcachedItem)
44: }
45: 
46: // GetByteArray returns the cached value as an byte array
47: func (s *memcachedStorage) Get(ctx context.Context, key string) ([]byte, error) {
48: 	memcachedItem, err := s.c.Get(key)
49: 	if errors.Is(err, memcache.ErrCacheMiss) {
50: 		return nil, ErrCacheItemNotFound
51: 	}
52: 
53: 	if err != nil {
54: 		return nil, err
55: 	}
56: 
57: 	return memcachedItem.Value, nil
58: }
59: 
60: // Delete delete a key from the cache
61: func (s *memcachedStorage) Delete(ctx context.Context, key string) error {
62: 	return s.c.Delete(key)
63: }
