{"content":"1: package remotecache
2: 
3: import (
4: 	"context"
5: 	"time"
6: 
7: 	"github.com/grafana/grafana/pkg/infra/db"
8: 	"github.com/grafana/grafana/pkg/infra/log"
9: )
10: 
11: var getTime = time.Now
12: 
13: const databaseCacheType = "database"
14: 
15: type databaseCache struct {
16: 	SQLStore db.DB
17: 	log      log.Logger
18: }
19: 
20: func newDatabaseCache(sqlstore db.DB) *databaseCache {
21: 	dc := &databaseCache{
22: 		SQLStore: sqlstore,
23: 		log:      log.New("remotecache.database"),
24: 	}
25: 
26: 	return dc
27: }
28: 
29: func (dc *databaseCache) Run(ctx context.Context) error {
30: 	ticker := time.NewTicker(time.Minute * 10)
31: 	for {
32: 		select {
33: 		case <-ctx.Done():
34: 			return ctx.Err()
35: 		case <-ticker.C:
36: 			dc.internalRunGC()
37: 		}
38: 	}
39: }
40: 
41: func (dc *databaseCache) internalRunGC() {
42: 	err := dc.SQLStore.WithDbSession(context.Background(), func(session *db.Session) error {
43: 		now := getTime().Unix()
44: 		sql := `DELETE FROM cache_data WHERE (? - created_at) >= expires AND expires <> 0`
45: 
46: 		_, err := session.Exec(sql, now)
47: 		return err
48: 	})
49: 
50: 	if err != nil {
51: 		dc.log.Error("failed to run garbage collect", "error", err)
52: 	}
53: }
54: 
55: func (dc *databaseCache) Get(ctx context.Context, key string) ([]byte, error) {
56: 	cacheHit := CacheData{}
57: 
58: 	err := dc.SQLStore.WithDbSession(ctx, func(session *db.Session) error {
59: 		exist, err := session.Where("cache_key= ?", key).Get(&cacheHit)
60: 
61: 		if err != nil {
62: 			return err
63: 		}
64: 
65: 		if !exist {
66: 			return ErrCacheItemNotFound
67: 		}
68: 
69: 		if cacheHit.Expires > 0 {
70: 			existedButExpired := getTime().Unix()-cacheHit.CreatedAt >= cacheHit.Expires
71: 			if existedButExpired {
72: 				err = dc.Delete(ctx, key) // ignore this error since we will return `ErrCacheItemNotFound` anyway
73: 				if err != nil {
74: 					dc.log.Debug("Deletion of expired key failed: %v", err)
75: 				}
76: 				return ErrCacheItemNotFound
77: 			}
78: 		}
79: 
80: 		return nil
81: 	})
82: 
83: 	return cacheHit.Data, err
84: }
85: 
86: func (dc *databaseCache) Set(ctx context.Context, key string, data []byte, expire time.Duration) error {
87: 	return dc.SQLStore.WithDbSession(ctx, func(session *db.Session) error {
88: 		var expiresInSeconds int64
89: 		if expire != 0 {
90: 			expiresInSeconds = int64(expire) / int64(time.Second)
91: 		}
92: 
93: 		// attempt to insert the key
94: 		sql := `INSERT INTO cache_data (cache_key,data,created_at,expires) VALUES(?,?,?,?)`
95: 		_, err := session.Exec(sql, key, data, getTime().Unix(), expiresInSeconds)
96: 		if err != nil {
97: 			// attempt to update if a unique constrain violation or a deadlock (for MySQL) occurs
98: 			// if the update fails propagate the error
99: 			// which eventually will result in a key that is not finally set
100: 			// but since it's a cache does not harm a lot
101: 			if dc.SQLStore.GetDialect().IsUniqueConstraintViolation(err) || dc.SQLStore.GetDialect().IsDeadlock(err) {
102: 				sql := `UPDATE cache_data SET data=?, created_at=?, expires=? WHERE cache_key=?`
103: 				_, err = session.Exec(sql, data, getTime().Unix(), expiresInSeconds, key)
104: 				if err != nil && dc.SQLStore.GetDialect().IsDeadlock(err) {
105: 					// most probably somebody else is upserting the key
106: 					// so it is safe enough not to propagate this error
107: 					return nil
108: 				}
109: 			}
110: 		}
111: 
112: 		return err
113: 	})
114: }
115: 
116: func (dc *databaseCache) Delete(ctx context.Context, key string) error {
117: 	return dc.SQLStore.WithDbSession(ctx, func(session *db.Session) error {
118: 		sql := "DELETE FROM cache_data WHERE cache_key=?"
119: 		_, err := session.Exec(sql, key)
120: 
121: 		return err
122: 	})
123: }
124: 
125: // CacheData is the struct representing the table in the database
126: type CacheData struct {
127: 	CacheKey  string
128: 	Data      []byte
129: 	Expires   int64
130: 	CreatedAt int64
131: }
